import "./Recipes.css";
import { Link } from "react-router-dom";
import UserNavbar from "./UserNavbar";


export default function Recipes() {
  const recipes = [
    { id: 1, title: "Spaghetti Carbonara", author: "Sarah Lee", views: 1200, image: "https://images.unsplash.com/photo-1504674900247-0877df9cc836" },
    { id: 2, title: "Grilled Chicken Salad", author: "John Doe", views: 950, image: "https://images.unsplash.com/photo-1604908177522-402dbf6cddc" },
  ];

  return (
    <div className="recipes-page">
      <h2>All Recipes</h2>

      <div className="recipes-grid">
        {recipes.map((recipe) => (
          <div className="recipe-card" key={recipe.id}>
            <img src={recipe.image} alt={recipe.title} />

            <div className="recipe-info">
              <h3>{recipe.title}</h3>
              <p>👤 {recipe.author}</p>
              <p>👁 {recipe.views} views</p>

              <Link to={`/recipes/${recipe.id}`} className="view-btn">
                View Recipe
              </Link>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
